// Normalize incoming content request and initialize pipeline state
const raw = $input.first().json;
const src = (raw && typeof raw.body === 'object' && raw.body !== null) ? raw.body : raw;
return {
  json: {
    requestId: src.requestId || 'REQ-' + Date.now(),
    topic: String(src.topic || '').trim(),
    brief: String(src.brief || '').trim(),
    qualityThreshold: typeof src.qualityThreshold === 'number' ? src.qualityThreshold : 7.5,
    maxRevisions: typeof src.maxRevisions === 'number' ? src.maxRevisions : 2,
    revisionCount: 0,
    currentDraft: null,
    previousDraft: null,
    feedbackNotes: null,
    review: null,
    passed: false,
    research: null,
    timestamp: new Date().toISOString()
  }
};

// Evaluate review result, compute pass/fail against threshold, prep state for loop or exit
const state = $input.first().json;
const overall = typeof state.review?.overall === 'number' ? state.review.overall : 0;
const threshold = typeof state.qualityThreshold === 'number' ? state.qualityThreshold : 7.5;
const passed = overall >= threshold;
const newRevisionCount = (state.revisionCount || 0) + 1;

return {
  json: {
    ...state,
    passed: passed,
    revisionCount: newRevisionCount,
    previousDraft: state.currentDraft,
    feedbackNotes: passed ? null : (state.review?.revisionNotes || 'Improve overall quality, address the issues list.')
  }
};

// Build the final response envelope
const s = $input.first().json;
return {
  json: {
    requestId: s.requestId,
    topic: s.topic,
    brief: s.brief,
    finalDraft: s.currentDraft,
    wordCount: s.draftWordCount || null,
    qualityPassed: s.passed === true,
    finalScore: s.review?.overall ?? null,
    scores: s.review?.scores || null,
    revisionCount: s.revisionCount,
    hitMaxRevisions: s.revisionCount >= s.maxRevisions && !s.passed,
    issues: s.review?.issues || [],
    reviewerNotes: s.review?.revisionNotes || null,
    timestamp: new Date().toISOString()
  }
};
